mapper.select:
SELECT COUNT(*)
FROM board_report_t


        AND status = #{status}


        AND target_type = #{targetType}

SELECT r.r_idx, r.target_type, r.target_idx, r.reporter, r.reason, r.status, r.reg_date, CASE WHEN r.target_type = 'POST' THEN b.title ELSE CONCAT('[댓글] ', b.title) END AS target_title, CASE WHEN r.target_type = 'POST' THEN b.content ELSE c.content END AS target_content, CASE WHEN r.target_type = 'POST' THEN b.author ELSE c.author END AS target_author FROM board_report_t r LEFT JOIN board_t b ON (r.target_type = 'POST' AND b.b_idx = r.target_idx) OR (r.target_type = 'COMMENT' AND b.b_idx = ( SELECT b2.b_idx FROM comment_t c2 JOIN board_t b2 ON c2.b_idx = b2.b_idx WHERE c2.c_idx = r.target_idx LIMIT 1 )) LEFT JOIN comment_t c ON r.target_type = 'COMMENT' AND c.c_idx = r.target_idx
AND r.status = #{status}
AND r.target_type = #{targetType}
ORDER BY r.reg_date DESC LIMIT #{offset}, #{pageSize}
